    #print(f"Nodes: {len(nodes)}, Bodies: {len(bodies)}")

    for i, coords in enumerate(bodies):
        #print(i)
        blender_coords = [convert_to_blender_coordinates(lat, lon, ele, scaleHor) for lat, lon, ele in coords]
