def toggle_console():
    try:
        if platform.system() == "Windows":
            bpy.ops.wm.console_toggle()
    except Exception as e:
        print(f"Could not toggle console: {e}")

def projection(operation, Mapobject, obj):

    if operation == "paint":
        merge_with_map(Mapobject, obj)

        obj.location.z += 1

        bpy.ops.object.origin_set(type='ORIGIN_CURSOR', center='MEDIAN')
        color_map_faces_by_terrain(Mapobject, obj)
        mesh_data = obj.data
        bpy.data.objects.remove(obj, do_unlink=True)
        bpy.data.meshes.remove(mesh_data)

    if operation == "separate":
        merge_with_map(Mapobject, obj, False)

        obj.data.materials.clear()

        obj.location.z += 0.2


    if operation == "singleColorMode":

        merge_with_map(Mapobject, obj,True)

        obj.data.materials.clear()


        thickerObj = single_color_mode_mesh_wireframe(obj,Mapobject)

        #remove_objects(thickerObj)

    if operation == "singleColorMode_remesh":

        merge_with_map(Mapobject, obj, True)

        obj.data.materials.clear()

        thickerObj = single_color_mode_mesh_remesh(obj, Mapobject)

    if operation == "negative":
        merge_with_map(Mapobject, obj,True)
        boolean_operation(Mapobject,obj,"DIFFERENCE")
        remove_objects(obj)

def delete_selected_verts(obj):
    # Must be in Edit Mode
    if obj.mode != 'EDIT':
        bpy.ops.object.mode_set(mode='EDIT')

    # Get the BMesh representation
    me = obj.data
    bm = bmesh.from_edit_mesh(me)

    # Gather selected vertices
    verts_to_delete = [v for v in bm.verts if v.select]

    # Use bmesh.ops to delete them
    # context='VERTS' also deletes connected edges and faces
    bmesh.ops.delete(bm, geom=verts_to_delete, context='VERTS')

    # Update the mesh and viewport
    bmesh.update_edit_mesh(me)

    
def importSVGtoMerge(Mapobject):


    svg_path = bpy.context.scene.tp3d.svg_path
    #svg_path = "C:/Users/marti/Downloads/arrow-down-left-svgrepo-com.svg"
    extrude_depth = 0.01
    scale_factor = 100.0

    # -----------------------
    # 1. Import SVG
    # -----------------------

    # Objects before import
    before = set(bpy.data.objects)
    before_collections = set(bpy.data.collections)

    bpy.ops.import_curve.svg(filepath=svg_path)

    # Objects after import
    after = set(bpy.data.objects)

    # Move SVG objects from the auto-created collection to Scene Collection and remove it
    scene_col = bpy.context.scene.collection
    for new_col in set(bpy.data.collections) - before_collections:
        for obj in list(new_col.all_objects):
            if not scene_col.objects.get(obj.name):
                scene_col.objects.link(obj)
        bpy.data.collections.remove(new_col, do_unlink=True)

    # Newly created objects
    svg_objs = [obj for obj in after - before if obj.type == 'CURVE']



    for obj in svg_objs:
        curve = obj.data
        
        # Curve setup (preserve holes)
        curve.dimensions = '2D'
        curve.fill_mode = 'BOTH'
        curve.use_fill_caps = True

        curve.bevel_depth = 0
        curve.bevel_resolution = 0

        curve.extrude = extrude_depth
        
        
        # Scale SVG
        obj.scale *= scale_factor


        # Convert to mesh
        bpy.ops.object.select_all(action='DESELECT')
        
        obj.select_set(True)
        bpy.context.view_layer.objects.active = obj
        
        bpy.ops.object.convert(target='MESH')

        bpy.ops.object.transform_apply(location=False, rotation=False, scale=True)


        bpy.ops.object.mode_set(mode='EDIT')

        bpy.ops.mesh.select_all(action='SELECT')
        bpy.ops.mesh.remove_doubles(threshold=0.0001)  # Works in all 2.8+ versions

        bpy.ops.object.mode_set(mode='OBJECT')
    
    bpy.ops.object.select_all(action='DESELECT')
    #for obj in svg_objs:
    svg = merge_objects(svg_objs)

    svg.select_set(True)
    bpy.context.view_layer.objects.active = svg

    bpy.ops.object.origin_set(
        type='ORIGIN_GEOMETRY',
        center='BOUNDS'
    )

    # Move object so origin is at world center
    svg.location = bpy.context.scene.cursor.location

    return svg
        
def read_gpx_and_create_heightmap(length=100.0, height=20.0):

    # Get file path
    gpx_file_path = bpy.context.scene.tp3d.get('file_path', None)
    if not gpx_file_path or not os.path.exists(gpx_file_path):
        print("Invalid or missing GPX file path.")
        return

    points = []
    total_distance = 0.0
    max_elevation = float('-inf')
    min_elevation = float('inf')
    prev_point = None

    separate_paths = read_gpx_file()
    temppoints = [item for sublist in separate_paths for item in sublist]

    for i, pnt in enumerate(temppoints):
        lat = pnt[0]
        lon = pnt[1]
        ele = pnt[2]
        elevation = ele if ele is not None else 0.0
        if prev_point:
            dist = haversine(prev_point[0], prev_point[1], lat, lon)
            total_distance += dist

        points.append((lat, lon, elevation, total_distance))
        max_elevation = max(max_elevation, elevation)
        min_elevation = min(min_elevation, elevation)
        prev_point = (lat, lon)

    if total_distance == 0 or not points:
        print("No valid points or zero-length route.")
        return

    # Create a 2D surface (closed shape)
    curve_data = bpy.data.curves.new(name='RouteProfile', type='CURVE')
    curve_data.dimensions = '2D'
    curve_data.fill_mode = 'BOTH'
    spline = curve_data.splines.new('POLY')
    spline.use_cyclic_u = True  # Close the shape

    # Add original points as elevation profile
    profile_points = []

    print(f"Min elevation: {min_elevation}")

    for lat, lon, elevation, distance in points:
        x = (distance / total_distance) * length - length/2
        y = ((elevation-min_elevation) / (max_elevation-min_elevation)) * (height-2) + 2
        profile_points.append((x, y))

    # Add bottom-left and bottom-right points to close the shape
    bottom_left = (profile_points[0][0], -0.0)
    bottom_right = (profile_points[-1][0], -0.0)

    full_points = profile_points + [bottom_right, bottom_left]

    spline.points.add(len(full_points) - 1)

    for i, (x, y) in enumerate(full_points):
        spline.points[i].co = (x, y, 0.0, 1.0)

    # Create and link the object
    curve_obj = bpy.data.objects.new("RouteProfileSurface", curve_data)
    bpy.context.collection.objects.link(curve_obj)

    # Convert to mesh and extrude
    bpy.context.view_layer.objects.active = curve_obj
    curve_obj.select_set(True)
    bpy.ops.object.convert(target='MESH')

    mesh_obj = bpy.context.object
    bpy.ops.object.mode_set(mode='EDIT')
    bpy.ops.mesh.select_all(action='SELECT')
    bpy.ops.mesh.extrude_region_move(TRANSFORM_OT_translate={"value": (0, 0, 1)})
    bpy.ops.object.editmode_toggle()

    print(f"Route length: {total_distance:.2f} meters")
    print(f"Maximum elevation: {max_elevation:.2f} meters")
    
    curve_obj.location = bpy.context.scene.cursor.location

    return curve_obj


